fields.description:
SpyCloud detected compromised credentials.
User: @{items('For_each_account')?['Name']}@@{items('For_each_account')?['UPNSuffix']}
Incident: @{triggerBody()?['object']?['properties']?['title']}
Severity: @{triggerBody()?['object']?['properties']?['severity']}
Actions taken: Password reset, sessions revoked

properties.query:
let vip_list = _GetWatchlist('SpyCloud-VIP-Watchlist') | project Email=tolower(Email);
let vip_fallback = datatable(Email:string)["ceo@","cfo@","cto@","ciso@","admin@","root@","vp@","director@","president@"];
let vips = union vip_list, (vip_fallback | where Email !in (vip_list | project Email));
SpyCloudBreachWatchlist_CL
| where TimeGenerated > ago(7d) and severity >= 5
| where tolower(email) in~ (vips | project Email) or email has_any ("ceo","cfo","cto","ciso","admin","root","vp-","director")
| project TimeGenerated, email, severity, breach_title, target_domain, infected_machine_id, password_type

